import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import Navbar from "../components/Navbar";
import axios from "axios";

function UploadScan() {

  const navigate = useNavigate();

  const [file, setFile] = useState(null);
  const [original, setOriginal] = useState(null);
  const [mask, setMask] = useState(null);
  const [highlight, setHighlight] = useState(null);

  const [history, setHistory] = useState([]);

  const user = localStorage.getItem("loggedUser");

  useEffect(() => {

    // 🔒 Protect page if not logged in
    if (!user) {
      alert("Please login to upload scans");
      navigate("/login");
      return;
    }

    const savedHistory = localStorage.getItem("scanHistory_" + user);

    if (savedHistory) {
      setHistory(JSON.parse(savedHistory));
    }

  }, [navigate, user]);

  const handleUpload = async () => {

    if (!file) {
      alert("Please select a file");
      return;
    }

    const formData = new FormData();
    formData.append("file", file);

    try {

      const response = await axios.post(
        "http://localhost:5000/predict",
        formData
      );

      const orig = "data:image/png;base64," + response.data.original;
      const m = "data:image/png;base64," + response.data.mask;
      const h = "data:image/png;base64," + response.data.highlight;

      setOriginal(orig);
      setMask(m);
      setHighlight(h);

      const newScan = {
        id: Date.now(),
        fileName: file.name,
        original: orig,
        mask: m,
        highlight: h
      };

      const updatedHistory = [newScan, ...history];

      setHistory(updatedHistory);

      localStorage.setItem(
        "scanHistory_" + user,
        JSON.stringify(updatedHistory)
      );

    } catch (error) {

      console.error(error);
      alert("Prediction failed");

    }
  };

  const loadScan = (scan) => {

    setOriginal(scan.original);
    setMask(scan.mask);
    setHighlight(scan.highlight);

  };

  return (

    <>
      <Navbar />

      <div className="container-fluid mt-4">

        <div className="row">

          {/* History Sidebar */}

          <div className="col-md-3 border-end">

            <h5>Scan History</h5>

            {history.length === 0 && (
              <p>No scans yet</p>
            )}

            {history.map((scan) => (

              <div
                key={scan.id}
                className="p-2 border mb-2"
                style={{ cursor: "pointer" }}
                onClick={() => loadScan(scan)}
              >
                {scan.fileName}
              </div>

            ))}

          </div>

          {/* Upload Section */}

          <div className="col-md-9">

            <h3>Upload MRI Scan</h3>

            <input
              type="file"
              className="form-control mb-3"
              onChange={(e) => setFile(e.target.files[0])}
            />

            <button
              className="btn btn-primary"
              onClick={handleUpload}
            >
              Predict
            </button>

            <div className="row mt-4">

              {original && (
                <div className="col-md-4 text-center">
                  <h5>Uploaded MRI</h5>
                  <img src={original} alt="original" width="220"/>
                </div>
              )}

              {mask && (
                <div className="col-md-4 text-center">
                  <h5>Tumor Mask</h5>
                  <img src={mask} alt="mask" width="220"/>
                </div>
              )}

              {highlight && (
                <div className="col-md-4 text-center">
                  <h5>Tumor Highlight</h5>
                  <img src={highlight} alt="highlight" width="220"/>
                </div>
              )}

            </div>

          </div>

        </div>

      </div>

    </>
  );
}

export default UploadScan;
